head.script:
//==================================================================================================================
// id       : fm_501_01_01b
// 이름     : 수금사항등록화면
// 경로     : 회계/청구/수금/채권/회계/수금사항등록
// 경로(2)  : 회계 > 자금관리 > 수금관리 > 수금사항등록 > 첫번째 탭
// 작 성 자 : 오영재
// 작 업 일 : 2026-1-7
// 사용계정 : 내부
// 비고     :
//
// 업로드   :
// 다운로드 : 
// 레포트   :
// 호출     : 
//==================================================================================================================

scwin.today = $c.date.getServerDateTime("yyyyMMdd");
scwin.strFromDate = scwin.today.substring(0, 6) + "01";
scwin.strToDate = scwin.today;
scwin.privAdmin = $c.gus.cfIsNull($c.data.getMemInfo("privAdmin")) ? '' : $c.data.getMemInfo("privAdmin");

scwin.checkSearch = false;		// 거래처 귀속부서 필수값으로 조회된지 여부 확인변수(채권용)
scwin.checkSearch1 = false;		// 거래처 귀속부서 필수값으로 조회된지 여부 확인변수(수금용)
scwin.checkRetrieveSave = "F";	// 저장에 의한 수금목록 재조회인지 여부 판단 T:저장에 의한 자동 재조회, F:조회버튼에 의한 재조회

scwin.vLoginCoCd = $c.gus.cfIsNull($c.data.getMemInfo("coCd")) ? '' : $c.data.getMemInfo("coCd");   // 소속 자회사
scwin.vLoginCoClsCd = $c.gus.cfIsNull($c.data.getMemInfo("coClsCd")) ? '' : $c.data.getMemInfo("coClsCd"); //회계_회사구분('CO035' : 0:동부 EXPRESS)
scwin.vUserHomeClsCd = $c.gus.cfIsNull($c.data.getMemInfo("userHomeClsCd")) ? '' : $c.data.getMemInfo("userHomeClsCd");    // 사용자소속구분코드 

scwin.g_sUserId = $c.gus.cfIsNull($c.data.getMemInfo("empNo")) ? '' : $c.data.getMemInfo("empNo");
scwin.gJudgeYn = "0";
scwin.gJudgeYnCommiSsionAmt = "0";

scwin.isSubCompany = false;

scwin.vMaxDt = "";
scwin.vMaxCloseYm = "";
scwin.checkFromDate = "";

scwin.bCheck = "0";

//hidden
scwin.hid_clntNo = ""
scwin.hid_acctDeptCd = ""
scwin.txtCoClsCd = "";
scwin.txt_apprvEmpEmail = "";

scwin.onpageload = function () {

    gr_acctRecv.setColumnStyle("mgntNo", "text-decoration", "underline");
    gr_acctRecv.setColumnStyle("mgntNo", "color", "blue");
    gr_acctRecv.setColumnStyle("mgntNo", "cursor", "pointer");
};

//-------------------------------------------------------------------------
// 대변 Grid내역 화면 Setting
//-------------------------------------------------------------------------
scwin.f_Setting = function () {

    if (lc_acctRecvClsCd.getValue() == "01") {
        //acctRecvId.style.display = "inline";
        //billRecvId.style.display = "none";
        //acctRecvId1.style.display = "inline";
        //billRecvId1.style.display = "none";
        gr_acctRecv.show();
        gr_billRecvDisho.hide();
        ed_grd_title.setValue("채권내역(대변)");

        // 채권처리시는 수수료, 선수금 입력가능하게 변경
        $c.gus.cfEnableObj(ed_initAmt, true);
        $c.gus.cfEnableObj(ed_commiSsionAmt, true);
        $c.gus.cfEnableObj(ed_commiSsionAmtFcrc, true);
    } else if (lc_acctRecvClsCd.getValue() == "02") {
        //acctRecvId.style.display = "none";
        //billRecvId.style.display = "inline";
        //acctRecvId1.style.display = "none";
        //billRecvId1.style.display = "inline";
        gr_acctRecv.hide();
        gr_billRecvDisho.show();
        ed_grd_title.setValue("부도어음(대변)");

        // 부도어음 처리시는 수수료 , 선수금 입력불가능하게 변경
        $c.gus.cfEnableObj(ed_initAmt, false);
        $c.gus.cfEnableObj(ed_commiSsionAmt, false);
        $c.gus.cfEnableObj(ed_commiSsionAmtFcrc, false);
        ed_initAmt.setValue("0");
        ed_commiSsionAmt.setValue("0");
        ed_commiSsionAmtFcrc.setValue("0.00");
    }
}

//-------------------------------------------------------------------------
// 초기화 시킬 내역들 정의
//-------------------------------------------------------------------------
scwin.f_Reset = function () {
    ed_initAmt.setValue("0");
    ed_commiSsionAmt.setValue("0");
    ed_commiSsionAmtFcrc.setValue("0.00");

    scwin.f_Setting();

}

//-------------------------------------------------------------------------
// 채권내역 및 수금수단 조회 
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function () {
    debugger;

    scwin.f_Setting();
    let ret;
    ret = await $c.gus.cfValidate([ed_coCd]);
    if (!ret)
        return;

    if (!$c.gus.cfIsAfterDate(ed_FromDate.getValue(), ed_ToDate.getValue())) {
        $c.gus.cfAlertMsg("수금예정 시작일자는 만기일자보다 이전 날짜 이어야 합니다.");
        ed_FromDate.focus();
        return;
    }

    if (!$c.gus.cfIsAfterDate(ed_collMoneyFromDate.getValue(), ed_collMoneyToDate.getValue())) {
        $c.gus.cfAlertMsg("입금일자 시작일자는 만기일자보다 이전 날짜 이어야 합니다.");
        ed_collMoneyToDate.focus();
        return;
    }

    // 조회 조건의 필수 입력 사항 체크
    if (ed_crn.getValue().trim() == "" && ed_sclntNo.getValue().trim() == "") {
        // 필수 조회조건 입력 여부(거래처) Check
        ret = await $c.gus.cfValidate([ed_sclntNo]);
        if (!ret) {
            return;
        }
    }

    ret = await $c.gus.cfValidate([ed_collMoneyFromDate, ed_collMoneyToDate, ed_FromDate, ed_ToDate, ed_sacctDeptCd]);
    if (!ret) {
        return;
    }



    // 수금수단에 대한 조회 일자를  수금일자의 조회 일자로 변경한다.
    // 유저의 조회 버튼에 의한 재조회 일경우만 수금수단 조회일자를 채권조회일자와 동일할게 변경한다.
    //	if ( checkRetrieveSave == "F" ) {
    //		ed_collMoneyFromDate.Text = ed_FromDate.Text;
    //		ed_collMoneyToDate.Text = ed_ToDate.Text;
    //	}


    if (lc_acctRecvClsCd.getValue() == "01") {
        //tr_searchAcctRecv.Post();
        //채권내역 조회 조건용 TR
        dma_searchAcctRecv.setJSON(scwin.rtnSearchParam('01'));
        $c.sbm.execute(sbm_searchAcctRecv);
    } else if (lc_acctRecvClsCd.getValue() == "02") {
        //tr_searchBillRecvDisho.Post();
        //부도어음 조회 조건용 TR
        dma_searchBillRecvDisho.setJSON(scwin.rtnSearchParam('02'));
        $c.sbm.execute(sbm_searchBillRecvDisho);
        //		f_Retrieve2();
    }

    //채권내역 선택금액 초기화
    ed_selectAmt.setValue("0");
    ed_selectAmtFcrc.setValue("0.00");

    //수금내역 선택금액 초기화
    ed_selectAmtCollMoney.setValue("0");
    ed_selectAmtFcrcCollMoney.setValue("0.00");
    dma_searchAcctRecv.set("repClntNo", "T");
    scwin.checkRetrieveSave = "F";	// 저장버튼에 의한 재조회인지 유저가 조회버튼을 클릭했는지 유무 확인 (전역변수)


    // 환차손익 초기화
    ed_gap.setValue("0");
    //f_Retrieve2();
    $c.gus.cfDisable([ed_gap]);

}

//-------------------------------------------------------------------------
// 수수료 10만원이상  입력 권한 조회.(그리드용)
//-------------------------------------------------------------------------
scwin.f_retrieveJudge = function () {
    //심사권한 조회
    /*
    ds_judge.DataId = "/cm.zz.RetrieveCommonPopupCMD.do?sysCd=CommonEBC"
                                + "&queryId=retrieveBorrowAcqKindInfo&param1=FM092";
    ds_judge.Reset();
    */
    $c.sbm.execute(sbm_judge);
}
scwin.f_retrieveJudgeCommiSsionAmt = function () {
    //수수료심사권한부서 조회(여객사업본부였을 경우 수수료의 금액제한을 푼다.
    /*
    ds_judgeCommiSsionAmt.DataId = "/cm.zz.RetrieveCommonPopupCMD.do?sysCd=CommonEBC"
                                    + "&queryId=retrieveJudgeCommiSsionAmtAcctDeptCd&param1="+ed_sacctDeptCd.text;
    ds_judgeCommiSsionAmt.Reset();
    */
    sbm_judgeCommiSsionAmt.action = "/cm.zz.RetrieveCommonPopupCMD.do?sysCd=CommonEBC"
        + "&queryId=retrieveJudgeCommiSsionAmtAcctDeptCd&param1=" + ed_sacctDeptCd.getValue();
    $c.sbm.execute(sbm_judgeCommiSsionAmt);
}

//-------------------------------------------------------------------------
// 수금수단 조회 
//-------------------------------------------------------------------------
scwin.f_Retrieve2 = async function () {

    let ret;
    ret = await $c.gus.cfValidate([ed_coCd]);
    if (!ret)
        return;

    if (!$c.gus.cfIsAfterDate(ed_collMoneyFromDate.getValue(), ed_collMoneyToDate.getValue())) {
        $c.gus.cfAlertMsg("입금일자 시작일자는 만기일자보다 이전 날짜 이어야 합니다.");
        ed_collMoneyToDate.focus();
        return;
    }

    // 조회 조건의 필수 입력 사항 체크
    if (ed_crn.getValue().trim() == "" && ed_sclntNo.getValue().trim() == "") {
        // 필수 조회조건 입력 여부(거래처명) Check
        if (lc_collMoneyCntSht.getValue() != "01") {
            ret = await $c.gus.cfValidate([ed_sclntNo]);
            if (!ret) {
                return;
            }
        }
    }

    // 조회 조건의 필수 입력 사항 체크
    ret = await $c.gus.cfValidate([ed_collMoneyFromDate, ed_collMoneyToDate]);
    if (!ret) {
        return;
    }

    //부서조회용 날짜(상단 그리드와 검색 변수명이 중복되어, 조회시에 다른 dataset로 보냄)
    //dma_searchCollMoney.ClearData();
    //dma_searchCollMoney.ImportData(ds_searchAcctRecv.ExportData(1, ds_searchAcctRecv.CountRow, false)); //수금수단 조회용 TEMP DATA에 넣는다.  
    //dma_searchCollMoney.setJSON(dma_searchAcctRecv.getJSON()); bind 가 달라서 따로 지정
    dma_searchCollMoney.setJSON(scwin.rtnSearchParam('01'));
    dma_searchCollMoney.set("queryDeptSearchStDate", ed_collMoneyFromDate.getValue());
    dma_searchCollMoney.set("queryDeptSearchEndDate", ed_collMoneyToDate.getValue());
    // 수금수단 조회 조건용 TR

    //tr_searchCollMoney.Post();
    $c.sbm.execute(sbm_searchCollMoney);

    //수금내역 선택금액 초기화
    ed_selectAmtCollMoney.setValue("0");
    ed_selectAmtFcrcCollMoney.setValue("0.00");
    dma_searchAcctRecv.set("repClntNo", "T");

    // 환차손익 초기화
    ed_gap.setValue("0");
    $c.gus.cfDisable([ed_gap]);

    ed_initAmt.setValue("0");
    ed_acctDeptCd.setValue("");
    ed_acctDeptNm.setValue("");
    ed_commiSsionAmt.setValue("0");
    ed_commiSsionAmtFcrc.setValue("0.00");

}

scwin.onUdcCompleted = function () {
    $c.gus.cfDisableKey();
    scwin.f_setCompanyInfo();

    ed_FromDate.setValue(scwin.strFromDate);
    ed_ToDate.setValue(scwin.strToDate);
    ed_collMoneyFromDate.setValue(scwin.strFromDate);
    ed_collMoneyToDate.setValue(scwin.strToDate);
    scwin.f_retrieveJudge();

    scwin.gJudgeYn = "0"
    for (var i = 0; i < ds_judge.getRowCount(); i++) {

        if (scwin.g_sUserId == ds_judge.getCellData(i, "col1")) {
            scwin.gJudgeYn = "1";
            break;
        }
        else {
            scwin.gJudgeYn = "0";
        }
    }

    ed_wrkDt.setValue(scwin.strToDate);		// 추가내역 작업일자 초기화

    ed_sclntNo.focus();
    lc_acctRecvClsCd.setSelectedIndex(0);
    scwin.f_Reset();
    dma_searchBillRecvDisho.set("billRecvStsCd", "-5");		// 부도어음, 할인후부도  2개의 상태를 조회한다.
    dma_searchAcctRecv.set("repClntNo", "T");		// 대표거래처사용유무
    dma_searchAcctRecv.set("profitGbn", "2");   //잡손익 모두 조회

    // 환차손익 초기화
    ed_gap.setValue("0");
    $c.gus.cfDisable([ed_gap]);

    //2026.04.02 자회사이면 회사코드 검색 창 비활성화
    if (scwin.vUserHomeClsCd == ACConstants.SUBSIDIARY_USER_HOME_CLS_CD) {
        $c.gus.cfDisableObjects([udc_coCd]);
    }
}

scwin.udc_coCd_onblurNameEvent = function (e) {
    ed_coCd.setValue("");
    scwin.f_PopUpCompanyInfo('T');
};

scwin.udc_coCd_onclickEvent = function (e) {
    scwin.f_PopUpCompanyInfo('F');
};

scwin.udc_sclntNo_onclickEvent = function (e) {
    scwin.f_openPopUp(ed_sclntNo, ed_sclntNm, '1', 'ALL');
};

scwin.udc_crn_onclickEvent = function (e) {
    scwin.f_openPopUp(ed_crn, ed_crnNm, '4', 'ALL');
};

scwin.udc_sacctDeptCd_onclickEvent = function (e) {
    scwin.f_openPopUp(ed_sacctDeptCd, ed_sacctDeptNm, '2', 'ALL');
};

scwin.btn_reset_onclick = function (e) {
    $c.gus.cfInitObjects(table1, []);
    scwin.f_setCompanyInfo();
};

scwin.btn_search_onclick = function (e) {
    scwin.f_Retrieve();
};

scwin.udc_sbankbookCd_onclickEvent = function (e) {
    scwin.f_openPopUp(ed_sbankbookCd, ed_sbankbookNm, '3', 'ALL');
};

scwin.btn_reset2_onclick = function (e) {
    $c.gus.cfInitObjects(table2, []);
};

scwin.f_Excel = function (gr) {
    // 'gr_collMoney'
}
scwin.btn_save_onclick = function (e) {
    scwin.f_Save();
};

scwin.btn_save2_onclick = function (e) {
    scwin.f_EtcLossProc();
};

//-------------------------------------------------------------------------
// 회사 변경시 초기화  
//------------------------------------------------------------------------- 
scwin.f_initObj = function () {
    $c.gus.cfInitObjects([ed_sclntNo, ed_sclntNm]); //거래처 
    $c.gus.cfInitObjects([ed_sacctDeptCd, ed_sacctDeptNm]); //청구귀속 
    $c.gus.cfInitObjects([ed_acctDeptCd, ed_acctDeptNm]); //선수금청구귀속부서 
    $c.gus.cfInitObjects([ed_sbankbookCd, ed_sbankbookNm]); //통장명   
}

scwin.udc_coCd_cb = function (rtnList) {

    // SET	 
    if (rtnList != null) {
        if (rtnList[0] == "N/A") return;
        if (ed_coCd.options.hidVal != rtnList[0]) {
            scwin.f_initObj();
            //ds_collMoney.ClearData();//회사코드변경시, 수금수단 그리드 초기화. 상단그리드의 cocd이용함.
            ds_collMoney.removeAll();
        }
        ed_coCd.setValue(rtnList[0]);	// 코드
        ed_coNm.setValue(rtnList[5]); // 회사명 
        ed_coCd.options.hidVal = rtnList[0];  // 히든값
        scwin.txtCoClsCd = rtnList[1];	// 회사구분   
    } else {
        ed_coCd.setValue("");
        ed_coNm.setValue("");
        ed_coCd.options.hidVal = "";
        scwin.txtCoClsCd = "";

        //ds_collMoney.ClearData()
        ds_collMoney.removeAll();
    }
    if (scwin.txtCoClsCd > ACConstants.CO_CLS_CD_DONGBU) {  	// 자회사 회계 시스템 
        scwin.isSubCompany = true;
    } else {
        scwin.isSubCompany = false;
    }

    scwin.f_JobCloseYN();
}

scwin.sbm_closeMonthChk_submitdone = function (e) {
    scwin.vMaxCloseYm = ds_closeMonthChk_rslt.getCellData(0, "col1");
    ds_closeMonthChk_rslt.removeAll();
    //alert("scwin.vMaxCloseYm => " + scwin.vMaxCloseYm);
}
scwin.sbm_closeMonthChk_submiterror = function (e) { }

//-------------------------------------------------------------------------
// 마감체크
//-------------------------------------------------------------------------
scwin.f_JobCloseYN = function () {
    let pCoCd = ed_coCd.getValue(); //회사코드

    /*
    ds_closeMonthChk.DataId = "/cm.zz.RetrieveCommonPopupCMD.do?sysCd=CommonEBC"
                                    + "&queryId=retrieveMaxCloseControlYearMonth"
                                    + "&param1=" + pCoCd + "&param8=01"
                                    ;
    ds_closeMonthChk.SyncLoad="true";
    ds_closeMonthChk.Reset();
    */

    dma_closeMonthChk.set("sysCd", "CommonEBC");
    dma_closeMonthChk.set("queryId", "retrieveMaxCloseControlYearMonth");
    dma_closeMonthChk.set("param1", pCoCd);
    dma_closeMonthChk.set("param8", "01");

    $c.sbm.execute(sbm_closeMonthChk);

    //vMaxCloseYm = ds_closeMonthChk.NameString(1,"col1");
}

scwin.f_checkFromDate = function () {
    scwin.checkFromDate = ed_FromDate.getValue();
}

//-------------------------------------------------------------------------
// 회사 입력 팝업 
//-------------------------------------------------------------------------
scwin.f_PopUpCompanyInfo = function (pWinCloseTF) {
    udc_coCd.setSelectId("retrieveDongbuGroupCompanyInfo");
    udc_coCd.cfCommonPopUp(scwin.udc_coCd_cb
        , ed_coCd.getValue(), ed_coNm.getValue()
        , pWinCloseTF, null, null, null, null
        , null, null, null, null, null);
}

//-------------------------------------------------------------------------
// 팝업결과
//-------------------------------------------------------------------------
scwin.f_resultPopUp = function (orgObjCd, orgObjNm, rtnList) {
    // 넘어온 OBJ가 EMEdit인지 TextBox인지 구분한다.
    if (rtnList != null) {
        if (rtnList[0] == "N/A") return;
        orgObjCd.setValue(rtnList[0]);	// 코드값
        orgObjNm.setValue(rtnList[1]);	// 코드명
        orgObjCd.options.hidVal = rtnList[0];	// HIDDEN 코드값
        orgObjNm.options.hidVal = rtnList[1];	// HIDDEN 코드명
    } else {
        orgObjCd.setValue("");
        orgObjNm.setValue("");
        orgObjCd.options.hidVal = "";
        orgObjNm.options.hidVal = "";
    }
}

scwin.udc_sclntNo_cb = function (rtnList) {
    scwin.f_resultPopUp(ed_sclntNo, ed_sclntNm, rtnList);
    scwin.checkSearch = false;	// 정상조회여부 확인
    scwin.checkSearch1 = false;	// 정상조회여부 확인
}
scwin.udc_sacctDeptCd_cb = function (rtnList) {
    scwin.f_resultPopUp(ed_sacctDeptCd, ed_sacctDeptNm, rtnList);
    scwin.checkSearch = false;	// 정상조회여부 확인
    scwin.checkSearch1 = false;	// 정상조회여부 확인    
}
scwin.udc_sbankbookCd_cb = function (rtnList) {
    //통장은 2번째에 통장명이 있기 때문에 1번째와 2번째의 위치를 변경해서 넘겨준다.
    if (rtnList != null) {
        let tempbankbookNm = rtnList[1];
        rtnList[1] = rtnList[2];
        rtnList[2] = tempbankbookNm;
        scwin.f_resultPopUp(ed_sbankbookCd, ed_sbankbookNm, rtnList);
    }
}
scwin.udc_crn_cb = function (rtnList) {
    scwin.f_resultPopUp(ed_crn, ed_crnNm, rtnList);
    scwin.checkSearch = false;	// 정상조회여부 확인
    scwin.checkSearch1 = false;	// 정상조회여부 확인
}
scwin.udc_acctDeptCd_cb = function (rtnList) {
    scwin.f_resultPopUp(ed_acctDeptCd, ed_acctDeptNm, rtnList);
}
scwin.udc_apprvEmpNo_cb = function (rtnList) {
    // 넘어온 OBJ가 EMEdit인지 TextBox인지 구분한다.
    if (rtnList != null) {
        if (rtnList[0] == "N/A") return;

        ed_apprvEmpNo.setValue(rtnList[0]);	// 승인자사번
        ed_apprvEmpNm.setValue(rtnList[1]);	// 승인자명
        scwin.txt_apprvEmpEmail = rtnList[2];	// 이메일주소

        if (scwin.txt_apprvEmpEmail == "") {
            $c.win.alert("승인자의 메일이 등록되어 있지 않습니다. IT담장자에게 문의하세요.");
            ed_apprvEmpNo.setValue("");	// 승인자사번
            ed_apprvEmpNm.setValue("");	// 승인자명
            scwin.txt_apprvEmpEmail = "";	// 이메일주소
            return;
        }

    } else {
        ed_apprvEmpNo.setValue("");	// 승인자사번
        ed_apprvEmpNm.setValue("");	// 승인자명
        scwin.txt_apprvEmpEmail = "";	// 이메일주소
    }
}
//-------------------------------------------------------------------------
// 각 Argument에 따른 PopUp을 호출 한다.
// 1:조회->거래처, 2:조회->수금귀속부서, 3:조회->통장번호
// code변수는 각 항목별 검색요청 값이다.
//-------------------------------------------------------------------------
scwin.f_openPopUp = function (orgObjCd, orgObjNm, select_code, flag) {

    // POPUP 돋보기 클릭시는 모든값을 조회 할 수 있도록 한다. flag:ALL일 경우는 돋보기 클릭한것임.
    // 넘어온 OBJ가 EMEdit인지 TextBox인지 구분한다.
    if (flag == "ALL") {
        cd = "";
        nm = "";
    } else {
        cd = orgObjCd.getValue();
        nm = orgObjNm.getValue();
    }

    let param = "";

    switch (select_code) {

        // 조회조건용 거래처 PopUp 호출
        case '1':
            param = "" + ed_coCd.getValue();	//자회사 회계시스템 추가사항

            udc_sclntNo.setSelectId("retrieveClntEmpNoList");
            udc_sclntNo.cfCommonPopUp(scwin.udc_sclntNo_cb, cd, nm, "T", null, null, null, null, param, null, null, null, null); // 거래처(모든 거래처를 다 조회한다.) 

            break;
        // 조회조건용 수금부서 PopUp 호출
        case '2':
            param = ed_FromDate.getValue().trim() + "," + ed_coCd.getValue() + "," + scwin.txtCoClsCd + ",,,"; //자회사 회계시스템 추가사항
            udc_sacctDeptCd.setSelectId("retrieveAcctDeptCdInfo6");
            udc_sacctDeptCd.cfCommonPopUp(scwin.udc_sacctDeptCd_cb, cd, nm, "T", null, null, null, null, param, "450", "500", null, null); // 귀속부서			

            break;
        case '3':
            param = ",,,,," + ed_coCd.getValue();	//자회사 회계시스템 추가사항
            udc_sbankbookCd.setSelectId("retrieveBankBookCdInfo");
            udc_sbankbookCd.cfCommonPopUp(scwin.udc_sbankbookCd_cb, cd, nm, "T", null, null, null, null, param, null, null, null, null); // 통장명

            break;
        case '4':
            // 사업자번호
            udc_crn.setSelectId("retrieveCrnInfo");
            udc_crn.cfCommonPopUp(scwin.udc_crn_cb, cd, nm, "T", null, null, null, null, null, null, null, null, null); //사업자번호

            break;

        case '5':
            // 선수금청구귀속부서 
            param = "," + ed_coCd.getValue() + "," + scwin.txtCoClsCd + ",0"; //자회사 회계시스템 추가사항
            udc_acctDeptCd.setSelectId("retrieveAcctDeptCdInfo6");
            udc_acctDeptCd.cfCommonPopUp(scwin.udc_acctDeptCd_cb, cd, nm, "T", null, null, null, null, param, null, null, null, null); // 귀속부서			

            break;

        case '6':
            // 수금요청 승인자 지정 
            param = ",,,"; //자회사 회계시스템 추가사항

            udc_apprvEmpNo.setSelectId("retrieveMailList2");
            udc_apprvEmpNo.cfCommonPopUp(scwin.udc_apprvEmpNo_cb, ed_apprvEmpNo.getValue(), "", "F", null, null, null, null, param, "450", "500", null, null);

            break;

        default:
            $c.gus.cfAlertMsg("잘못된 Function호출 입니다. 관리자에게 문의하시기 바랍니다.");
            break;
    }
}

//-------------------------------------------------------------------------
// PopUp창에서 사용되는 각 Cd,Nm에 대해서 POPUP표시 및 해당 값이 없을경우는 코드와 이름을 초기화 시킨다.
// flag값이 CD:코드변경이 없으면 POPUP안뛰움, NM:무조건 POPUP뛰움
//-------------------------------------------------------------------------
scwin.f_CheckPopUp = function (orgObjCd, orgObjNm, select_code, flag) {
    // debugger;
    // if (flag == "CD") {
    //     if (orgObjCd.getValue() == orgObjCd.options.hidVal) {
    //         return;
    //     } else {
    //         orgObjNm.setValue("");
    //     }
    // } else {
    //     if (orgObjNm.getValue() == orgObjNm.options.hidVal) {
    //         return;
    //     } else {
    //         orgObjCd.setValue("");
    //         orgObjCd.options.hidVal = "";
    //     }
    // }

    // 정상조회여부 확인
    if (select_code == "1" || select_code == "2" || select_code == "4") {
        scwin.checkSearch = false;
        scwin.checkSearch1 = false;
    }

    if (orgObjCd.getValue().trim() != "" || flag == "NM") {
        if (orgObjNm.getValue().trim() != "" || flag == "CD") {
            orgObjCd.setValue(orgObjCd.getValue().trim());
            orgObjNm.setValue(orgObjNm.getValue().trim());
            scwin.f_openPopUp(orgObjCd, orgObjNm, select_code, "NO");
        }
    } else {
        orgObjNm.setValue("");
        orgObjCd.setValue("");
        orgObjCd.options.hidVal = "";
    }
}

