//-------------------------------------------------------------------------
// 보험대차 채권 수수료 금액 입력 여부 CHECK
//-------------------------------------------------------------------------
scwin.f_CheckInsrLndcar = function () {
    let ctrtPatternCd = "";
    for (var ii = 0; ii < ds_acctRecv.getRowCount(); ii++) {
        if (ds_acctRecv.getCellData(ii, "num") == "T") {
            ctrtPatternCd = ds_acctRecv.getCellData(ii, "ctrtPatternCd");	// 계약유형 : 보험대차(2)
            if (ctrtPatternCd == "2" && parseInt(ds_acctRecv.getCellData(ii, "acctRecvOutbrDt")) >= 20080801 &&
                (parseInt(dma_addCollMoney.get("initAmt")) != 0
                    || parseInt(dma_addCollMoney.get("commiSsionAmt")) != 0
                    || parseFloat(dma_addCollMoney.get("commiSsionAmtFcrc")) != 0)
            ) {
                $c.gus.cfAlertMsg("렌터카 보험대차 채권은 수수료를 입력할 수 없습니다.");
                return false;
            }
        }
    }
    return true;
}

//-------------------------------------------------------------------------
// 수금 등록시 보험대차 채권은 1개만 수금 가능 : 보험대차채권+일반채권 Or 보험대차채권+보험대차채권 불가
//-------------------------------------------------------------------------
scwin.f_CheckInsrLndcarAcctMulti = function () {
    let ctrtPatternCd = "";
    let insrCnt = 0;	// 보험대차 채권 수
    let acctCnt = 0;	// 전체 채권 수
    for (let ii = 1; ii < ds_acctRecv.getRowCount(); ii++) {
        if (ds_acctRecv.getCellData(ii, "num") == "T") {
            acctCnt = acctCnt + 1;
            ctrtPatternCd = ds_acctRecv.getCellData(ii, "ctrtPatternCd");	// 계약유형 : 보험대차(2)
            if (ctrtPatternCd == "2") {
                insrCnt = insrCnt + 1;
            }
            if (acctCnt > 1 && insrCnt > 0) {
                $c.gus.cfAlertMsg("렌터카 보험대차 채권은 다른 채권과 함께 수금처리할 수 없습니다.");
                return false;
            }
        }
    }
    return true;
}
