scwin.gr_acctRecv_onheaderclick = function (headerId) {
    let sum = 0;
    let sumFcrc = 0;
    scwin.bCheck = (scwin.bCheck == "0") ? "1" : "0";

    if (headerId == "hNum") {
        var checkedLen = 0;
        for (var idx = 0; idx < ds_acctRecv.getRowCount(); idx++) {
            if (ds_acctRecv.getCellData(idx, "num") == "T") {
                checkedLen++
                break;
            }
        }

        if (checkedLen > 0) {
            for (i = 0; i < ds_acctRecv.getRowCount(); i++) {
                ds_acctRecv.setCellData(i, "num", "T");
                sum = sum + Number(ds_acctRecv.getCellData(i, "ramt"));
                sumFcrc = sumFcrc + Number(ds_acctRecv.getCellData(i, "ramtFcrc"));
                ds_acctRecv.setCellData(i, "checkNum", "T");
            }
        } else {
            for (i = 0; i < ds_acctRecv.CountRow; i++) {
                ds_acctRecv.setCellData(i, "num", "F");
                ds_acctRecv.setCellData(i, "checkNum", "F");
            }
            sum = 0;
            sumFcrc = 0;
        }
    }

    ed_selectAmt.setValue(sum);
    ed_selectAmtFcrc.setValue(sumFcrc);
};

scwin.ed_commiSsionAmtFcrc_onblur = function (e) {
    if (ed_commiSsionAmtFcrc.getValue() == 0 || ed_commiSsionAmtFcrc.getValue()) {
        ed_commiSsionAmtFcrc.setValue(parseFloat(ed_commiSsionAmtFcrc.getValue()).toFixed(2));
    }
};

/*
<!--  체크박스 변경시  -->
<script language=JavaScript for=ds_collMoney event=onColumnChanged(row,colid)>
*/
scwin.ds_collMoney_oncelldatachange = function (info) {
    let colid = info.colID;
    let row = info.rowIndex;
    //작업일자는 선택한 수금수단의 입금일자가 가장 큰 날짜로 변경한다.
    let vMaxDt2 = "";
    let vMaxDt3 = "";

    let vCheckBillReceivable = 0;	// 수금항목중 받을어음 선택 여부확인
    let vCheckSuspInit = 0;		// 수금항목중 가수/선수금 선택 여부 확인
    let vCheckInit = 0;			// 선수금 선택여부 확인

    if (colid == "num") {
        for (var i = 0; i <= ds_collMoney.getRowCount(); i++) {
            if (ds_collMoney.getCellData(i, "num") == "T") {
                // 받을 어음을 선택했는지 여부 확인
                if (ds_collMoney.getCellData(i, "acctCd") == ACConstants.ACCTCD_BILLRECEIVABLE_CHECK ||
                    ds_collMoney.getCellData(i, "acctCd") == ACConstants.ACCTCD_BILLRECEIVABLE_STOCK ||
                    ds_collMoney.getCellData(i, "acctCd") == ACConstants.ACCTCD_BILLRECEIVABLE_ELECT ||
                    ds_collMoney.getCellData(i, "acctCd") == ACConstants.ACCTCD_BILLRECEIVABLE_PROMISE) {
                    vCheckBillReceivable++;
                    //가수/선수 선택여부
                } else if (ds_collMoney.getCellData(i, "acctCd") == ACConstants.ACCTCD_INITAMT) {
                    vCheckSuspInit++; //가수/선수 선택여부
                    // 선수금 선택여부 확인
                } else if (ds_collMoney.getCellData(i, "acctCd") == ACConstants.ACCTCD_SUS_RECV) {
                    vCheckInit++;
                }

                if (vCheckBillReceivable > 0) {
                    if (vCheckSuspInit > 0) {
                        $c.win.alert("수금수단 계정항목이 서로 다른것은 선택할수 없습니다.");
                        ds_collMoney.setCellData(row, "num", "F");
                        return;
                    } else if (vCheckInit > 0) {
                        $c.win.alert("수금수단 계정항목이 서로 다른것은 선택할수 없습니다.");
                        ds_collMoney.setCellData(row, "num", "F");
                        return;
                    }
                } else if (vCheckSuspInit > 0) {
                    if (vCheckBillReceivable > 0) {
                        $c.win.alert("수금수단 계정항목이 서로 다른것은 선택할수 없습니다.");
                        ds_collMoney.setCellData(row, "num", "F");
                        return;
                    } else if (vCheckInit > 0) {
                        $c.win.alert("수금수단 계정항목이 서로 다른것은 선택할수 없습니다.");
                        ds_collMoney.setCellData(row, "num", "F");
                        return;
                    }
                } else if (vCheckInit > 0) {
                    if (vCheckBillReceivable > 0) {
                        $c.win.alert("수금수단 계정항목이 서로 다른것은 선택할수 없습니다.");
                        ds_collMoney.setCellData(row, "num", "F");
                        return;
                    } else if (vCheckSuspInit > 0) {
                        $c.win.alert("수금수단 계정항목이 서로 다른것은 선택할수 없습니다.");
                        ds_collMoney.setCellData(row, "num", "F");
                        return;
                    }
                }

                if (ds_collMoney.getCellData(i, "acctCd") == ACConstants.ACCTCD_BILLRECEIVABLE_CHECK ||
                    ds_collMoney.getCellData(i, "acctCd") == ACConstants.ACCTCD_BILLRECEIVABLE_STOCK ||
                    ds_collMoney.getCellData(i, "acctCd") == ACConstants.ACCTCD_BILLRECEIVABLE_ELECT ||
                    ds_collMoney.getCellData(i, "acctCd") == ACConstants.ACCTCD_BILLRECEIVABLE_PROMISE) {//받을어음을 선택했을경우

                    if (ds_collMoney.getCellData(i, "changeDt") == "") {
                        if (scwin.vMaxCloseYm >= ds_collMoney.getCellData(i, "susRecvInitamtOutbrDt").substr(0, 6)) { // 마감된 월이면 현재일자로 셋팅
                            scwin.vMaxDt = scwin.strToDate;
                        } else {  //마감되지 않았을때 선택한 입금일자
                            scwin.vMaxDt = ds_collMoney.getCellData(i, "susRecvInitamtOutbrDt");
                        }
                    } else {
                        if (scwin.vMaxCloseYm >= ds_collMoney.getCellData(i, "changeDt").substr(0, 6)) { // 마감된 월이면 현재일자로 셋팅
                            scwin.vMaxDt = scwin.strToDate;
                        } else {  //마감되지 않았을때 선택한 선수금전환일자
                            scwin.vMaxDt = ds_collMoney.getCellData(i, "changeDt");
                        }
                    }
                } else if (ds_collMoney.getCellData(i, "acctCd") == ACConstants.ACCTCD_INITAMT) {// 선수금을 선택했을경우
                    if (scwin.vMaxCloseYm >= ds_collMoney.getCellData(i, "changeDt").substr(0, 6)) { // 마감된 월이면 현재일자로 셋팅
                        scwin.vMaxDt = scwin.strToDate;
                    } else {  //마감되지 않았을때 선택한 선수금전환일자
                        scwin.vMaxDt = ds_collMoney.getCellData(i, "changeDt");
                    }
                } else if (ds_collMoney.getCellData(i, "acctCd") == ACConstants.ACCTCD_SUS_RECV) {// 가수금을 선택했을경우
                    if (scwin.vMaxCloseYm >= ds_collMoney.getCellData(i, "susRecvInitamtOutbrDt").substr(0, 6)) { // 마감된 월이면 현재일자로 셋팅
                        scwin.vMaxDt = scwin.strToDate;
                    } else {  //마감되지 않았을때 선택한 입금일자
                        scwin.vMaxDt = ds_collMoney.getCellData(i, "susRecvInitamtOutbrDt");
                    }
                }

                for (var j = 0; j < ds_collMoney.getRowCount(); j++) {
                    if (ds_collMoney.getCellData(j, "num") == "T") {
                        vMaxDt2 = ds_collMoney.getCellData(j, "susRecvInitamtOutbrDt");
                        vMaxDt3 = ds_collMoney.getCellData(j, "changeDt");
                        if (scwin.vMaxDt < vMaxDt2) {
                            scwin.vMaxDt = vMaxDt2;
                            if (scwin.vMaxDt < vMaxDt3) {
                                scwin.vMaxDt = vMaxDt3;
                            }
                        }
                    }
                }
            }
        }
        ed_wrkDt.setValue(scwin.vMaxDt);
    }
};

