scwin.f_GridToExcel = async function () {

    var gubun = lc_acctRecvClsCd.getValue();//채권종류 01 채권 02 부도어음
    var fName = ''; // 액셀 다운로드 파일명
    var fSheetName = '';

    if (gubun == '01') {
        btn_grid_group_1.setGridId('gr_acctRecv');

        if (ds_acctRecv.getRowCount() <= 0) {
            $c.win.alert("내역이 존재하지않습니다.");
            return false
        }
        fName = '채권내역';
        fSheetName = '채권내역';

        let sheetTitle = "채권내역";
        let gridId = gr_acctRecv;
        let infoArr = [];
        let options = {
            fileName: sheetTitle + ".xlsx",    // + ".xls",
            sheetName: sheetTitle,
            startRowIndex: 1,  // 내용 앞으로 몇 row 띄우는지...
        };

        var calcaulatedColnum = 0;
        for (var idx = 0; idx < ds_acctRecv.getTotalCol(); idx++) {
            if (gr_acctRecv.getColumnVisible(gr_acctRecv.getColumnID(idx))) {
                calcaulatedColnum++;
            }
        }

        infoArr = [
            //제목
            {
                rowIndex: 0               //제목을 표시할 행 index
                , colIndex: 0               //제목을 표시할 열 index
                , rowSpan: 1                //병합할 행의 수
                , colSpan: calcaulatedColnum                //병합할 열의 수
                , text: "채권내역(대변)"          //표시할 내용(제목)
                , textAlign: "center"       //표시할 내용의 정렬 방법(left, center, right)
                , fontSize: "9px"          //폰트 size
                , fontWeight: "bold"
                , fontName: "굴림"        //폰트이름 
                //, drawBorder: false       //cell의 border 지정(true, false)
                // ,useFooter:"true"        //다운로드시 Footer를 출력 할지 여부( "true"인경우 출력, "false"인경우 미출력)
            }];


        await $c.data.downloadGridViewExcel(gridId, options, infoArr);
        //cfGridToExcel(gr_groupCode, gridName, gridName + ".xls", 4 + 8 + 16);
        //await $c.data.downloadGridViewExcel(gr_acctRecv, { fileName: fName + ".xlsx", sheetName: fSheetName, useFooter: "false" });
    } else if (gubun == '02') {
        if (ds_billRecvDisho.getRowCount() <= 0) {
            $c.win.alert("내역이 존재하지않습니다.");
            return false
        }
        fName = '부도어음';
        fSheetName = '부도어음';
        btn_grid_group_1.setGridId('gr_billRecvDisho');
        await $c.data.downloadGridViewExcel(gr_billRecvDisho, { fileName: fName + ".xlsx", sheetName: fSheetName, useFooter: "false" });
    }
    btn_grid_group_1.setGridId()
};

// AsIs 와 달리 매개 변수를 못 주므로 따로 만든다.
// 하단 엑셀 f_GridToExcel(ds_collMoney, gr_collMoney,'수금수단')
scwin.f_GridToExcel2 = async function () {

    if (ds_collMoney.getRowCount() <= 0) {
        $c.win.alert("내역이 존재하지않습니다.");
        return false
    }

    var options = {
        fileName: "수금수단",    // + ".xls",
        sheetName: "수금수단",
        startRowIndex: 1,  // 내용 앞으로 몇 row 띄우는지...
    };

    var calcaulatedColnum = 0;
    for (var idx = 0; idx < ds_collMoney.getTotalCol(); idx++) {
        if (gr_collMoney.getColumnVisible(gr_collMoney.getColumnID(idx))) {
            calcaulatedColnum++;
        }
    }

    var infoArr = [
        //제목
        {
            rowIndex: 0               //제목을 표시할 행 index
            , colIndex: 0               //제목을 표시할 열 index
            , rowSpan: 1                //병합할 행의 수
            , colSpan: calcaulatedColnum                //병합할 열의 수
            , text: "수금수단(차변)"        //표시할 내용(제목)
            , textAlign: "center"       //표시할 내용의 정렬 방법(left, center, right)
            , fontSize: "9px"          //폰트 size
            , fontWeight: "bold"
            , fontName: "굴림"        //폰트이름 
            //, drawBorder: false       //cell의 border 지정(true, false)
            // ,useFooter:"true"        //다운로드시 Footer를 출력 할지 여부( "true"인경우 출력, "false"인경우 미출력)
        }];

    $c.data.downloadGridViewExcel(gr_collMoney, options, infoArr)
};

scwin.gr_acctRecv_oncellclick = function (Row, columnIndex, Colid) {

    if (Colid == 'num') {
        if (ds_acctRecv.getCellData(Row, "num") == "T" && Colid == "num" && ds_acctRecv.getCellData(Row, "checkNum") == "F") {
            ed_selectAmt.setValue(parseInt(ed_selectAmt.getValue()) + parseInt(ds_acctRecv.getCellData(Row, "ramt")));
            ed_selectAmtFcrc.setValue((parseFloat(ed_selectAmtFcrc.getValue()) + parseFloat(ds_acctRecv.getCellData(Row, "ramtFcrc"))).toFixed(2));
            ds_acctRecv.setCellData(Row, "checkNum", "T");

            // 그리드 체크시 카운트값 초기화
            var chkA = 0;
            var chkB = 0;
            var crcCd1 = "";
            var crcCd2 = "";

            // 채권내역 그리드
            for (var i = 1; i <= ds_acctRecv.countRow; i++) {
                if (ds_acctRecv.getCellData(i, "num") == "T") {
                    chkA++;
                }
            }

            // 수금내역 그리드
            for (var j = 1; j <= ds_collMoney.countRow; j++) {
                if (ds_collMoney.getCellData(j, "num") == "T") {
                    chkB++;
                }
            }

            if ((chkA != 0) && (chkB != 0)) {

                // 수금, 채권중 하나식은 선택했을 경우 둘중 하나는 원화, 하나는 외화일 경우
                for (var i = 0; i < ds_acctRecv.getRowCount(); i++) {
                    if (ds_acctRecv.getCellData(i, "num") == "T") {
                        crcCd1 = ds_acctRecv.getCellData(i, "crcCd");
                    }
                }

                for (var j = 0; j < ds_collMoney.countRow; j++) {
                    if (ds_collMoney.getCellData(j, "num") == "T") {
                        crcCd2 = ds_collMoney.getCellData(j, "crcCd");
                    }
                }

                if (((crcCd1 != ACConstants.KRW) && (crcCd2 == ACConstants.KRW)) || ((crcCd1 == ACConstants.KRW) && (crcCd2 != ACConstants.KRW))) {
                    ed_gap.setValue(ed_selectAmtCollMoney.getValue() - ed_selectAmt.getValue());
                    $c.gus.cfEnable(ed_gap);
                } else {
                    ed_gap.setValue(0);
                    $c.gus.cfDisable(ed_gap);
                }
            }
        } else if (ds_acctRecv.getCellData(Row, "num") == "F" && Colid == "num" && ds_acctRecv.getCellData(Row, "checkNum") == "T") {
            ed_selectAmt.setValue(parseInt(ed_selectAmt.getValue()) - parseInt(ds_acctRecv.getCellData(Row, "ramt")));
            ed_selectAmtFcrc.setValue((parseFloat(ed_selectAmtFcrc.getValue()) - parseFloat(ds_acctRecv.getCellData(Row, "ramtFcrc"))).toFixed(2));
            ds_acctRecv.setCellData(Row, "checkNum", "F");

            // 그리드 체크시 카운트값 초기화
            var chkA = 0;
            var chkB = 0;
            var crcCd1 = "";
            var crcCd2 = "";

            // 채권내역 그리드
            for (var i = 0; i < ds_acctRecv.getRowCount(); i++) {
                if (ds_acctRecv.getCellData(i, "num") == "T") {
                    chkA++;
                }
            }

            // 수금내역 그리드
            for (var j = 0; j <= ds_collMoney.getRowCount(); j++) {
                if (ds_collMoney.getCellData(j, "num") == "T") {
                    chkB++;
                }
            }

            if ((chkA != 0) && (chkB != 0)) {

                // 수금, 채권중 하나식은 선택했을 경우 둘중 하나는 원화, 하나는 외화일 경우
                for (var i = 0; i < ds_acctRecv.countRow; i++) {
                    if (ds_acctRecv.getCellData(i, "num") == "T") {
                        crcCd1 = ds_acctRecv.getCellData(i, "crcCd");
                    }
                }

                for (var j = 0; j < ds_collMoney.countRow; j++) {
                    if (ds_collMoney.getCellData(j, "num") == "T") {
                        crcCd2 = ds_collMoney.getCellData(j, "crcCd");
                    }
                }

                if (((crcCd1 != ACConstants.KRW) && (crcCd2 == ACConstants.KRW)) || ((crcCd1 == ACConstants.KRW) && (crcCd2 != ACConstants.KRW))) {
                    ed_gap.setValue(ed_selectAmtCollMoney.getValue() - ed_selectAmt.getValue());
                    $c.gus.cfEnable(ed_gap);
                } else {
                    ed_gap.setValue(0);
                    $c.gus.cfDisable(ed_gap);
                }
            }
        }
    }

    if (Colid == 'mgntNo') {
        var paramObj = {
            "sellVatNo": ds_acctRecv.getCellData(Row, Colid),
        };

        $c.win.openMenu("세금계산서 통합 발행", "/ui/ds/fs/bilg/fs_202_06_10b.xml", "fs_202_06_10b.jsp", paramObj);
    }
};



